function solve(grid: number[][], x: number, y: number, k: number): number[][] {
    // Create a copy of the grid to avoid modifying the original
    const result = grid.map(row => [...row]);

    // Extract the submatrix
    const submatrix = [];
    for (let i = 0; i < k; i++) {
        const row = [];
        for (let j = 0; j < k; j++) {
            row.push(result[x + i][y + j]);
        }
        submatrix.push(row);
    }

    // Reverse the submatrix
    const reversedSubmatrix = submatrix.reverse();

    // Replace the submatrix in the result
    for (let i = 0; i < k; i++) {
        for (let j = 0; j < k; j++) {
            result[x + i][y + j] = reversedSubmatrix[i][j];
        }
    }

    return result;
}
